import{_ as a}from"./chunks/serbija_order_screenshot.wr7iINSk.js";import{_ as r,c as t,o,ag as i}from"./chunks/framework.DRADY2L-.js";const f=JSON.parse('{"title":"FPV in Serbia Guide","description":"This page contains notes from the FPV community in Serbia: spot maps, chat links, flying regulations, and more. The laws are quite relaxed: Up to 900 grams -...","frontmatter":{"description":"This page contains notes from the FPV community in Serbia: spot maps, chat links, flying regulations, and more. The laws are quite relaxed: Up to 900 grams -...","gitAuthors":["mituritsyn"]},"headers":[],"relativePath":"theworld/Serbija.md","filePath":"en/theworld/Serbija.md","lastUpdated":1774721624000}'),n={name:"theworld/Serbija.md"};function l(s,e,p,h,d,u){return o(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="fpv-in-serbia-guide" tabindex="-1">FPV in Serbia Guide <a class="header-anchor" href="#fpv-in-serbia-guide" aria-label="Permalink to &quot;FPV in Serbia Guide&quot;">​</a></h1><p>This page contains notes from the FPV community in Serbia: spot maps, chat links, flying regulations, and more.</p><h2 id="laws" tabindex="-1">Laws <a class="header-anchor" href="#laws" aria-label="Permalink to &quot;Laws&quot;">​</a></h2><p>The laws are quite relaxed:</p><p>Up to 900 grams - Category 1, registration is only required if:</p><ul><li>You fly above 100 meters</li><li>Near airports</li><li>More than 500m away from yourself</li><li>Over people</li><li>Near people (30m)</li><li>Near prohibited zones</li><li>At night</li><li>The drone is carrying something</li></ul><p>👉 <a href="https://cad.gov.rs/upload/Bespilotni%20vazduhoplovi/Pravilnik_o_bespilotnim_vazduhoplovima_Sl_glasnik_RS_broj_108-15-nova-eng.pdf" target="_blank" rel="noreferrer">Link to regulations</a></p><h2 id="chats-and-servers" tabindex="-1">Chats and Servers <a class="header-anchor" href="#chats-and-servers" aria-label="Permalink to &quot;Chats and Servers&quot;">​</a></h2><p>👉 <a href="https://forms.gle/cth6sK1sMgeXBMg8A" target="_blank" rel="noreferrer">FPV in Serbia, main chat for Russian-speaking pilots on Telegram</a></p><p>👉 <a href="https://t.me/fpvserbia" target="_blank" rel="noreferrer">FPV Serbia 🇷🇸, English chat on Telegram (low activity)</a></p><p>👉 <a href="https://invite.viber.com/?g2=AQB9gM56j3yFlEs4e%2F7A94xbBJcwGi7nr5CTWxWHJXALXGFkZTGxQX4rYcpHe5Dz" target="_blank" rel="noreferrer">FPV Srbija, Serbian chat on Viber</a></p><p>👉 <a href="https://invite.viber.com/?g2=AQAimw9t307HcUs3whI3srAvqUWrYAAoMDVUc7qpP4%2B4wZbSl%2BdMHDDY5RK8nt3V" target="_blank" rel="noreferrer">RC BERZA, buy/sell on Viber in Serbian</a></p><p>👉 <a href="https://selective-tarragon-f1b.notion.site/FPV-3aaf0c40d79b44f398d7982da1cf2b33?pvs=4" target="_blank" rel="noreferrer">Russian-speaking community marketplace</a></p><p>👉 <a href="https://discord.gg/3W55nkAA" target="_blank" rel="noreferrer">Discord server for simulator flights</a></p><p>👉 <a href="https://fpv.rs/" target="_blank" rel="noreferrer">Serbian forum (low activity)</a></p><h2 id="maps" tabindex="-1">Maps <a class="header-anchor" href="#maps" aria-label="Permalink to &quot;Maps&quot;">​</a></h2><p>🗺️ <a href="https://cad.gov.rs/lat/strana/23311/bespilotni-vazduhoplovi" target="_blank" rel="noreferrer">Official no-fly zone map</a></p><p>🗺️ <a href="https://maps.app.goo.gl/HJ2VQ9K3NeJfHJ3XA" target="_blank" rel="noreferrer">FPV spots map on Google Maps (editable)</a></p><p>🗺️ <a href="https://www.bpl.rs/en/approved-flights-map/" target="_blank" rel="noreferrer">Another map with no-fly zones</a></p><p>According to Sergei Orekhov, top places worth driving to for flying:</p><p>Far away:</p><ol><li>Tara National Park - on the border with Bosnia near Montenegro (3.5 hours by car from Belgrade);</li><li>Fruška Gora National Park - not far from Novi Sad, you can take a train there in half an hour and then taxi (or 1 hour by car from Belgrade);</li><li>Golubac Fortress - a beautiful freestyle location like from simulators, but flying might not be allowed there) (2 hours);</li><li>Uvac - a place with deep canyons and river valley (3.5 hours);</li><li>Stara Planina National Park - a mountain park with waterfalls (3.5 hours);</li></ol><p>Relatively close:</p><ol><li>Avala - small hills with a beautiful view of sunset Belgrade (about 30 min).</li></ol><h2 id="shopping" tabindex="-1">Shopping <a class="header-anchor" href="#shopping" aria-label="Permalink to &quot;Shopping&quot;">​</a></h2><p>🛍️ <a href="https://docs.google.com/spreadsheets/d/19KzPUGUyeNiDDC7pDzb1e0e0x0PTzwcWPI2U6mR1TV0/edit?usp=sharing" target="_blank" rel="noreferrer">Joint order list from drone-fpv-racer.com (DFR)</a></p><h3 id="guide-how-to-order-from-europe-without-paying-huge-import-taxes" tabindex="-1">Guide: How to order from Europe without paying huge import taxes <a class="header-anchor" href="#guide-how-to-order-from-europe-without-paying-huge-import-taxes" aria-label="Permalink to &quot;Guide: How to order from Europe without paying huge import taxes&quot;">​</a></h3><p>Contact DE PREVOZ. <a href="https://deprevoz.com/" target="_blank" rel="noreferrer">Their website</a>.</p><p>Steps:</p><ol><li><p>Write to Ivan on Viber (he understands English) to get your address and details to specify on the package. <a href="viber://add?number=381645985589" target="_blank" rel="noreferrer">Link for smartphone</a> and <a href="viber://chat?number=+381645985589" target="_blank" rel="noreferrer">for PC version</a>.</p></li><li><p>You&#39;ll receive instructions like this:</p><blockquote><p>The procedure is as follows, You buy and pay online and send to our warehouse in Germany. When it arrives there in the first next tour, we bring it to Serbia. Price is from 5€ per kilogram, minimum charge 20€ for packages from 0 to 4kg. Send invoices to <a href="mailto:ukprevozin@gmail.com" target="_blank" rel="noreferrer">ukprevozin@gmail.com</a> &gt; *Note for packages outside the EU (China, America, UK, CH, Norway) that are subject to customs. You can buy only packages for which you can pay the tax online because we are no longer able to pay the tax for you.</p></blockquote></li><li><p>And an address like this (in this format with your details):</p><blockquote><p>Ordering address:</p><p>Name: ID International</p><p>Last name: SorekhovBg</p><p>Address: Osterholzallee 140 - 2.3</p><p>Postal code: 71636</p><p>City: Ludwigsburg</p><p>Phone: +4915904632469</p></blockquote></li><li><p>Enter the received details for delivery (screenshot example from fpv-racer in France).</p></li></ol><p align="center"><img src="'+a+'" width="600" alt="delivery address example from fpv-racer in France, screenshot"></p><ol start="5"><li><p>Select Germany as the delivery country, make sure that European VAT is included in the prices at checkout (19% I think, to avoid issues with German customs), choose a convenient delivery method (since taxes are paid, you can choose free DHL Express, delivery to the warehouse takes a day or two).</p></li><li><p>Monitor the package via DHL. From the moment it arrives at their warehouse, delivery to Serbia takes about a week (maybe faster, maybe a bit longer; they run the truck 4 times a month, nearest dates are usually on the <a href="https://deprevoz.com/datumi-polaska-html" target="_blank" rel="noreferrer">website</a>, but may differ by a day or two).</p></li><li><p>Wait for an SMS to your Serbian number (better not to message Ivan on Viber, everything will arrive) that you specified, or a message on Viber/WhatsApp saying the package has arrived</p><blockquote><p>(&#39;Jutro..</p><p>Samo da proverim,dobili poruku za danasnju podelu pakete od 10h do 12h na parkingu Ekstra centra,Omladinskih brigada 100?</p><p>Nenad,pozz)</p></blockquote></li><li><p>Go to the Ekstra shopping center parking lot (Omladinskih brigada 100), head to the far end from the entrance and look for a yellow van where two people will be handing out packages, pay them 20 euros or however much the delivery costs, and leave with your package.</p></li></ol>',32)])])}const g=r(n,[["render",l]]);export{f as __pageData,g as default};
